"use strict";(globalThis.webpackChunkbitcoin_junioren=globalThis.webpackChunkbitcoin_junioren||[]).push([[709],{6709(a){a.exports=JSON.parse('{"ui":{"greeting":"Ahoy, {name}! \ud83c\udff4\u200d\u2620\ufe0f","title":"Bitcoin don Yara","subtitle":"Gano duniyar kudi, daraja, da Bitcoin!","progress":"Ci gaba","newPlayer":"Fara dan wasa sabo","newPlayerConfirm":"Fara dan wasa sabo? Ci gaban yanzu zai gushe.","footer":"An gina shi bisa Bitcoin don Yara na My First Bitcoin \xb7 CC BY-SA 4.0","nameScreen":{"title":"Ahoy, mai cesanta!","subtitle":"Menene sunanka?","placeholder":"Sunanka...","button":"Fara cesanta! \ud83d\ude80"},"activity":{"back":"\u2190 Koma baya","next":"Na gaba \u2192","finish":"Kammala! \ud83c\udf89","correct":"Daidai!","wrong":"Kuskure","score":"Maki","tryAgain":"Sake gwadawa","completed":"An gama!","badgeEarned":"Ka sami alama!"},"sort":{"instruction":"Ja daga mai araha zuwa mai tsada","check":"Duba tsari","cheap":"\ud83d\udcb0 Mai arha","expensive":"\ud83d\udc8e Mai tsada","perfect":"\ud83c\udf89 Cikakke!","almost":"Kusan! Ka gyara jerin."},"categorize":{"instruction":"Ja zuwa nau\'i da ya dace","remaining":"Har yanzu {count} ya rage \u2014 ina wannan ya kamata?","check":"Duba!","score":"{score} / {total} daidai!"},"match":{"instruction":"Ha\u0257a nau\'i-nau\'i","old":"\ud83c\udfdb\ufe0f Tsoho","new":"\ud83d\ude80 Sabo","allDone":"\ud83c\udf89 Duk an ha\u0257a!"},"truefalse":{"public":"Bayyane","private":"Sirri","score":"{score} / {total} daidai!"},"cipher":{"instruction":"Karya lambar sirri da farantin lambobi","wheel":"Farar lamba \u2014 matsawa","challenge":"\u0198alubale","hint":"Taimako","placeholder":"Rubuta kalmar...","check":"Duba","allDone":"An karya duk lambobin!","next":"Ci gaba \u2192"},"mining":{"instruction":"Nemo nau\'i-nau\'i masu kama da juna","mined":"An ha\u0199a","attempts":"Yunkuri","done":"An kammala toshe a cikin {moves} yun\u0199uri!","next":"Ci gaba \u2192"},"scramble":{"instruction":"Warware kalmar da aka gurbata","hint":"Taimako","placeholder":"Rubuta kalmar...","check":"Duba","allDone":"An sami duk kalmomi!"},"moduleView":{"back":"\u2190 Koma baya","map":"\u2190 Taswirar Dukiya","coreIdea":"\ud83d\udca1 Babban Ra\'ayi","activities":"Ayyuka","module":"Sashe"},"activityTypes":{"quiz":"Tambayoyi","sort":"Tsarawa","match":"Ha\u0257awa","cipher":"Karya Lambobi","mining":"Tunawa","truefalse":"Bayyane/Sirri","categorize":"Rarraba","scramble":"Warware Kalma"},"common":{"continue":"Ci gaba \u2192","next":"Na gaba \u2192","result":"Sakamakon","correct":"\u2705 Daidai!","wrong":"\u274c Ba daidai ba gaba \u0257aya.","score":"{score} / {total} daidai!"},"quiz":{"perfect":"Duk daidai!","great":"Kyakkyawan aiki!","practice":"Ci gaba da atisaye!"}},"modules":[{"id":1,"title":"Musanya, Daraja & Farashi","icon":"\u2693","color":"#D97706","bg":"#FEF3C7","summary":"Daraja ya dogara da abin da kake bukata. Farashi shine nawa abu ya kai. Kudi yana warware matsalar musanya.","description":"Gano dalilin da yasa muke amfani da kudi da kuma ainihin darajar abubuwa!","badge":"\ud83c\udfdd\ufe0f Dan Kasuwar Tsibiri","activities":[{"type":"quiz","title":"Rayuwa a Tsibiri","intro":"Jirgin ruwan ka ya nutse kuma ka zo wani tsibiri maras zama!","questions":[{"q":"Ka isa wani tsibiri marar zama. Mene ne mafi daraja?","options":["\ud83d\udc8e Lu\'u-lu\'u","\ud83d\udd2a Wuka mai kaifi","\ud83d\udcf1 Wayar hannu","\ud83d\udcb0 Naira 100"],"correct":1,"explanation":"A tsibiri, da wuka za ka iya yanke itace, yanke abinci, kuma gina mafaka. Kudi da lu\'u-lu\'u ba su da amfani a can!"},{"q":"Kana da sanduna 5 na kamun kifi amma ba ka da tanti. Ma\u0199wabcinka yana da tanti 3 amma ba shi da sanda. Me za ku yi?","options":["Dukkanku ku jira","Musanya: sanda \u0257aya don tanti \u0257aya!","Babu komai, rashin sa\'a","Ku kuka tare"],"correct":1,"explanation":"Musanya ita ce tsohuwar hanyar ciniki! Ka ba da abin da ka wuce bukatarka don abin da kake bukata."},{"q":"Me yasa musanya wani lokaci yana da wahala?","options":["Domin yana da ban gajiya","Domin dole ka sami mutumin da yake son daidai abin da kake da shi","Domin an haramta shi","Domin kaya suna da nauyi"],"correct":1,"explanation":"Ana kiransa \'saduwar bukata\'. Kudi yana warware wannan matsala \u2014 kowa yana kar\u0253ar kudi!"},{"q":"A da ana amfani da harsashi a matsayin kudi. Menene abin da ke sa wani abu zama kudi mai kyau?","options":["Dole ya kasance mai kyau","Dole ya zama da \u0199aranci, mai \u0257aukarwa, kuma kowa ya yarda da shi","Dole ya zama abinci","Dole ya fito daga gwamnati"],"correct":1,"explanation":"Kudi mai kyau yana da \u0199aranci (ba a samu shi yadda ake so), ana iya \u0257auke shi cikin sau\u0199i, kuma kowa yana kar\u0253a shi a matsayin biyan ku\u0257i."},{"q":"Kwalbar ruwa tana farashi \u20a6200 a kantin sayarwa. A hamada, wani yana ba ka \u20a610,000 don wannan kwalbar. Me yasa?","options":["Kantin ya fi tsada","Domin ruwa a hamada yana da \u0199aranci \u0199warai kuma yana da muhimmanci sosai","Ruwa ne daban","Hamada na nesa"],"correct":1,"explanation":"\u0198aranci yana canza daraja! \u0198arancin abu da kuma yadda kake bukata shi, haka darajansa take \u0199aruwa."},{"q":"Menene bambanci tsakanin farashi da daraja?","options":["Babu bambanci","Farashi shine nawa abu ya kai, daraja shine muhimmancin abu gare ka","Farashi koyaushe ya fi daraja","Daraja na game da kudi kawai"],"correct":1,"explanation":"Zanen \u0257anko \u0257anka mai yiwuwa ba shi da farashi amma yana da daraja matu\u0199a. Farashi da daraja ba \u0257aya ba ne!"}]},{"type":"sort","title":"Layin Farashi","intro":"Ka shirya kayayyaki daidai daga mafi araha zuwa mafi tsada!","items":[{"name":"\ud83c\udf4e Tuffa","value":1},{"name":"\ud83d\udcd6 Littafi","value":2},{"name":"\u26bd \u0198wallon \u0199afa","value":3},{"name":"\ud83d\udcf1 Wayar hannu","value":4},{"name":"\ud83d\udef5 Motar scoota","value":5},{"name":"\ud83c\udfe0 Gida","value":6}]}]},{"id":2,"title":"Lokaci, Makamashi & Lada","icon":"\u26a1","color":"#0D9488","bg":"#CCFBF1","summary":"Makamashi yana da iyaka. Daidaituwa tsakanin aiki, hutawa, da wasa yana da muhimmanci. Ha\u0199uri yana kawo sakamako mafi kyau.","description":"Ta yaya kake amfani da lokacinmu da makamashinku? Kuma me yasa jira wani lokaci yana da hankali?","badge":"\u23f3 Maigadin Lokaci","activities":[{"type":"categorize","title":"Aiki, Hutawa ko Wasa?","intro":"Ja kowane aiki zuwa nau\'i da ya dace!","categories":["\ud83d\udcbc Aiki","\ud83d\ude34 Hutawa","\ud83c\udfae Wasa"],"items":[{"name":"Yin homework","cat":0},{"name":"Barci","cat":1},{"name":"Wasan \u0199wallon \u0199afa","cat":2},{"name":"Tsabtace \u0257aki","cat":0},{"name":"Karanta littafi","cat":1},{"name":"Wasan kama-kama","cat":2},{"name":"Shimfi\u0257a tebur","cat":0},{"name":"\u018aan barci","cat":1},{"name":"Wasan video","cat":2},{"name":"Sayan kaya kasuwa","cat":0},{"name":"Sauraron ki\u0257a","cat":1},{"name":"Wasan hawa bishiya","cat":2}]},{"type":"quiz","title":"Za\u0253in Lokaci","intro":"Ka za\u0253i YANZU ko DAGA BAYA?","questions":[{"q":"A labarin \u01b3a\u01b4an aladu uku: wane gida ya tsaya tsayin daka?","options":["\ud83c\udf3e Na ciyawa (an gina da sauri)","\ud83e\udeb5 Na itace (na tsakiya)","\ud83e\uddf1 Na tubali (ya \u0257auki mafi yawan lokaci)"],"correct":2,"explanation":"Gidan tubali ya \u0257auki mafi yawan lokaci da \u0199o\u0199ari, amma shi ka\u0257ai ya tsaya tsayin daka. Ha\u0199uri yana lada!"},{"q":"Menene ma\'anar \'\u0199arancin son lokaci yanzu\'?","options":["Kana son duk komai YANZU","Kana shirye ka jira don wani abu mafi kyau","Ba ka da agogon hannu","Kana barci da yawa"],"correct":1,"explanation":"\u0198arancin son lokaci yanzu = shirye ka jira don sakamako mafi kyau. Kamar \u0257an alade da ya gina gidan tubali!"},{"q":"Za a ba ka alewa 1 yanzu, ko alewa 3 idan ka jira mintuna 10. Mene ne za\u0253in mafi hankali?","options":["Alewa 1 YANZU!","Jira: alewa 3 > alewa 1","Alewa ba shi da kyau ga lafiya","Gudu"],"correct":1,"explanation":"Wannan shi ne gwajin alewa na shahara! Yara da suka iya jira sun samu sakamako mafi kyau a makaranta daga baya."},{"q":"Kana da muhimman jarrabawa gobe. Menene \u0199arancin son lokaci yanzu?","options":["Yin wasa yanzu ka karanta gobe","Karanta yau domin ka yi kyau gobe","Tsallake jarrabawar","Fata sa\'a"],"correct":1,"explanation":"Yin wani abu mai wahala yanzu (karatu) domin samun wani abu mai kyau daga baya (maki mai kyau) \u2014 wannan \u0199arancin son lokaci yanzu ne."},{"q":"Me zai faru idan ka kashe duk makamashinku da safe?","options":["Za ka zama mai \u0199arfi","Ba ka da komai don sauran rana","Za ka samu ikon allahntaka","Babu wani abu na musamman"],"correct":1,"explanation":"Makamashi yana da iyaka! Raba shi da hankali yana da muhimmanci \u2014 kamar kudi."}]}]},{"id":3,"title":"Na Gargajiya da na Zamani","icon":"\ud83d\udd04","color":"#7C3AED","bg":"#EDE9FE","summary":"Fasaha tana canzawa koyaushe. Kowane \u0199ir\u0199iro yana warware matsala. Ba duk sabon abu ne mafi kyau ba ta atomatik.","description":"Daga tattabarar wasi\u0199a zuwa intanet \u2014 yadda fasaha take canza duniya!","badge":"\ud83d\ude80 Majagaba na Fasaha","activities":[{"type":"match","title":"Tsoho \u2194 Sabo","intro":"Ha\u0257a kowane tsohon fasaha da sigar zamani!","pairs":[{"old":"\u2709\ufe0f Wasi\u0199a","new":"\ud83d\udce7 Imel"},{"old":"\ud83d\udcde Tarho na zawo","new":"\ud83d\udcf1 Wayar hannu"},{"old":"\ud83d\uddfa\ufe0f Taswira ta takarda","new":"\ud83d\udccd GPS"},{"old":"\ud83d\udcf7 Firam \u0257in fim","new":"\ud83d\udcf8 Kyamara ta dijital"},{"old":"\ud83d\udcf0 Jarida","new":"\ud83c\udf10 Shafin labarai na yanar gizo"},{"old":"\ud83d\udcb0 Tsabar kudi","new":"\u20bf Bitcoin"}]},{"type":"quiz","title":"Yi Tunani game da Gaba","intro":"Yaya fasaha za ta kasance bayan shekaru 20?","questions":[{"q":"Me yasa fasaha take canzawa a tsawon lokaci?","options":["Domin tsohuwar fasaha tana \u0253arna","Domin mutane suna warware matsaloli da sabbin \u0199ir\u0199irori","Domin gwamnati tana so","Ba tare da wata dalilin ba"],"correct":1,"explanation":"Kowane \u0199ir\u0199iro yana warware matsala. Mota ta warware matsalar cewa dawakai suna jin gajiya kuma suna tafiya a hankali!"},{"q":"Shin sabbin fasahohi KOYAUSHE suna mafi kyau fiye da na tsofaffi?","options":["Eh, koyaushe","A\'a, wani lokaci tsohon abu ya fi kyau ko amincewa","Sabbin fasahohi ba su wanzu ba","Kawai idan sun fi tsada"],"correct":1,"explanation":"Littafi na takarda ba ya bu\u0199atar batir! Wani lokaci tsofaffin hanyoyin warware matsala har yanzu suna da hankali."},{"q":"Bitcoin ku\u0257i ne na dijital. Menene ya ha\u0257a shi da tsohuwar harsashi?","options":["Dukkansu suna fitowa daga teku","Dukkansu suna da \u0199aranci ana amfani da su a matsayin hanyar musanya","Babu komai","Dukkansu kyauta ne"],"correct":1,"explanation":"Harsashi da Bitcoin dukkansu suna da \u0199aranci (akwai adadi iyakacin) kuma ana amfani da su a matsayin hanyar musanya."},{"q":"Menene \u0199ir\u0199iro?","options":["Sayen wani sabon abu","Wani ingantaccen ci gaba ko \u0199ir\u0199iro da ke warware matsala","Wani kalma mai wahala da ba ta da ma\'ana","Don masana kimiyya ka\u0257ai"],"correct":1,"explanation":"\u0198ir\u0199iro = sabuwar hanya ko mafi kyawun hanya don warware matsalar da ke wanzu. Kowa zai iya \u0199ir\u0199iro!"}]}]},{"id":4,"title":"Aminci & Sirri","icon":"\ud83d\udee1\ufe0f","color":"#DC2626","bg":"#FEE2E2","summary":"Kai ne ke yanke shawarar bayanan da kake raba. Lambobi na sirri suna kare sa\u0199onni. Ba a bu\u0199atar amana idan kana da \u0253oyayyen rubutu.","description":"Lambobin sirri, sirri, da yadda ake kare kanka akan layi!","badge":"\ud83d\udd10 Cypherpunk","activities":[{"type":"truefalse","title":"Bayyane ko Sirri?","intro":"Shin wannan bayanin bayyane ne ko sirri? Yanke shawarar da sauri!","statements":[{"text":"Kalmar shigar ka","answer":false,"label":"Sirri!","explanation":"Kalmar shigar koyaushe sirri ce. Kada ka raba ta da kowa!"},{"text":"Sunanka a makaranta","answer":true,"label":"Bayyane","explanation":"A makaranta kowa yana san sunanka \u2014 wannan bayanin bayyane ne."},{"text":"Lambar PIN \u0257inka","answer":false,"label":"Sirri!","explanation":"Lambar PIN \u0257inka asiri ne \u2014 tana kare asusun bankin ka."},{"text":"Wurin shakatawa a gari","answer":true,"label":"Bayyane","explanation":"Wurin shakatawa wuri ne na jama\'a \u2014 kowa na iya zuwa."},{"text":"Diyanrinka","answer":false,"label":"Sirri!","explanation":"Diyanrinka sirri ne \u2014 kai ka\u0257ai ke yanke shawarar wanda zai iya karantawa."},{"text":"Launi na kekanka","answer":true,"label":"Bayyane","explanation":"Kowa zai iya ganin launin kekanka."},{"text":"Adireshin gidanka","answer":false,"label":"Sirri!","explanation":"Ba ka raba adireshi da ba\u0199i \u2014 wannan bayanin sirri ne."},{"text":"Yanayin yau","answer":true,"label":"Bayyane","explanation":"Yanayi iri \u0257aya ne ga kowa \u2014 bayyane gaba \u0257aya!"},{"text":"Makullin Bitcoin \u0257inka","answer":false,"label":"Sirri!","explanation":"Makullin sirri \u0257inka shine mafi muhimmancin asiri. Wanda ya samu shi yana da bitcoin \u0257inka!"}]},{"type":"cipher","title":"Lambar Sirri","intro":"Karya kalmomin Bitcoin na asiri da farantin lambobi!"}]},{"id":5,"title":"Al\'amuran Kudi","icon":"\ud83c\udfe6","color":"#B45309","bg":"#FEF3C7","summary":"Kuna iya samun kudi, ajiye shi, zuba jari, da kashe shi. Kasafin kudi za\u0253i ne. Dokokin gaskiya suna da muhimmanci.","description":"Samun kudi, ajiyewa, zuba jari \u2014 zama masanin kudi!","badge":"\ud83d\udc8e Mai Hikimar Kudi","activities":[{"type":"quiz","title":"Hankali da Kudi","intro":"Gwada yadda kake da hankali game da al\'amuran kudi!","questions":[{"q":"Menene ajiyar kudi?","options":["Kashe kudi nan take","Ajiye kudi don amfani daga baya","Jefar da kudi","Aron kudi daga aboki"],"correct":1,"explanation":"Ajiyar kudi = adana kudi domin ka iya sayen wani abu mafi girma ko muhimmanci daga baya."},{"q":"Menene zuba jari?","options":["\u0181oye kudi","Saka ku\u0257inka ko lokacinku a wani wuri domin ya fi daraja daga baya","Kashe duk yau","\u0198one kudi"],"correct":1,"explanation":"Zuba jari shine saka ku\u0257inka ko lokacinku a wani wuri da fatan zai fi daraja daga baya."},{"q":"Kana da harsashi 12. Tanti yana farashi 8 kuma sanda yana farashi 6. Shin zaka iya sayen dukkansu?","options":["Eh!","A\'a, 8 + 6 = 14, amma kana da 12 kawai","Kawai da ragi","Harsashi ba kudi ba ne"],"correct":1,"explanation":"8 + 6 = 14, amma kana da harsashi 12 kawai. Dole ka za\u0253a! Wannan yin kasafin kudi ne."},{"q":"A gwanjon sayarwa, farashi na wani kayan da ba kasafai ba yana \u0199aruwa koyaushe. Me yasa?","options":["Mai siyarwa yana da mugunta","Mutane da yawa suna so amma akwai \u0257aya kawai (\u0199aranci + bu\u0199ata)","Abu yana \u0199aruwa girma","Domin wani yana yaudara"],"correct":1,"explanation":"Idan mutane da yawa suna so amma ka\u0257an ne akwai, farashin yana \u0199aruwa. Haka bu\u0199ata da samar da kayayyaki ke aiki!"},{"q":"Me yasa dokokin gaskiya suna da muhimmanci game da kudi?","options":["Ba su da muhimmanci","Domin kowa ya samu daidaitaccen dama","Ga yara kawai","Domin ya zama mafi wahala"],"correct":1,"explanation":"Dokokin gaskiya suna tabbatar da cewa ba wanda zai iya yaudara kuma kowa yana da daidaitaccen dama."},{"q":"Menene aro?","options":["Sata kudi","Kar\u0253ar ku\u0257in wani da za ka biya daga baya","Ajiye kudi","Rasa kudi"],"correct":1,"explanation":"Aro yana nufin kar\u0253ar ku\u0257in wani, amma dole ka biya shi daga baya \u2014 yawanci tare da \u0199arin (riba)."}]}]},{"id":6,"title":"Asasin Bitcoin","icon":"\u20bf","color":"#EA580C","bg":"#FFF7ED","summary":"Bitcoin ku\u0257i ne na dijital mai \u0199aranci ba tare da mai tsaka-tsaki ba. Mining yana tabbatar da ma\'amaloli. Satoshi ya kasance \u0253oye.","description":"Babban cesantar Bitcoin: daga Satoshi zuwa mining!","badge":"\u26cf\ufe0f Mai hakar Bitcoin","activities":[{"type":"quiz","title":"Wane ne Satoshi?","intro":"Gano tarihin da ke bayan Bitcoin!","questions":[{"q":"Wane ne ya \u0199ir\u0199iri Bitcoin?","options":["Elon Musk","Satoshi Nakamoto","Banki","Google"],"correct":1,"explanation":"Satoshi Nakamoto ya buga \'white paper\' a 2008 tare da ra\'ayin Bitcoin. Ba wanda ya san wane ne Satoshi a zahiri!"},{"q":"Menene \'white paper\'?","options":["Takarda fanko","Takarda da kake bayyana sabon ra\'ayi a ciki","Wasi\u0199ar sirri","Aikin makaranta"],"correct":1,"explanation":"White paper takarda ce da kake gabatar da sabon ra\'ayi ko warware matsala ga duniya."},{"q":"Menene Genesis Block?","options":["Wasan kwamfuta","Farkon farkon katafaren Bitcoin","Wani nau\'in dutse","Wata kalmar sirri"],"correct":1,"explanation":"A ranar 3 ga Janairun 2009 aka \u0199ir\u0199iri Genesis Block \u2014 farkon farkon katafaren a cikin blockchain na Bitcoin."},{"q":"Nawa na bitcoin za a ta\u0253a samu?","options":["Maras iyaka","Miliyan 21 kawai","Daidai biliyan 1","Ba wanda ya sani"],"correct":1,"explanation":"Ba za a ta\u0253a samun bitcoin fiye da miliyan 21 ba. Wannan \u0199arancin an gina shi cikin dokokin!"},{"q":"Menene \'tona\' a Bitcoin?","options":["Tona \u0199asa","Amfani da kwamfutoci warware damtse don tabbatar da ma\'amaloli","Buga bitcoin","Zanen bitcoin"],"correct":1,"explanation":"Masu tona suna amfani da kwamfutoci don warware damtsolin lissafi. A matsayin hujjar aiki da suka yi, ana ba su damar tabbatar da ma\'amaloli."},{"q":"Menene Proof of Work?","options":["Rahoto daga makaranta","Hujja cewa wani ya yi \u0199o\u0199ari na gaske don samun wani abu","Kalmar sirri","Wani nau\'in takardar sheda"],"correct":1,"explanation":"Proof of Work = hujjar aiki. Kamar wasan kwallon: kowa yana bin dokokin iri \u0257aya kuma yana da daidaitaccen dama."},{"q":"Me yasa Satoshi ya \u0253ace?","options":["Ya tafi hutu","Yiwuwa don ya sa Bitcoin ya zama na kowa, ba tare da shugaba ba","Ya yi fushi","Ba ya wanzu"],"correct":1,"explanation":"Ta wurin \u0253acewa, Satoshi ya tabbatar da cewa Bitcoin ba na mutum \u0257aya ba ne. Cibiyar sadarwa tana gudana bisa dokoki, ba bisa shugaba ba."}]},{"type":"mining","title":"Tona Bitcoin!","intro":"Nemo nau\'i-nau\'i masu kama da juna don tona katafaren \u2014 kamar masu tona na gaske!"},{"type":"scramble","title":"Warware Kalmar Bitcoin","intro":"Warware kalmomin Bitcoin da aka gurbata!","words":[{"scrambled":"IDUKNA","answer":"KUDINA","hint":"Ku\u0257i na dijital"},{"scrambled":"ROAKI","answer":"KARIKO","hint":"Mai \u0199ir\u0199iro na asiri"},{"scrambled":"FRAKATA","answer":"KATAFAR","hint":"Ma\'amaloli suna ciki"},{"scrambled":"RANCIKA","answer":"KARANCI","hint":"Ba a samu yawa ba"},{"scrambled":"ANATONA","answer":"TONAANA","hint":"Warware damtse da kwamfuta"},{"scrambled":"JKUABUN","answer":"JAKUBUN","hint":"Inda kake adana bitcoin"}]}]}]}')}}]);